import { BaseModel } from './base-model';
import { Plan } from './plan';

export class SubscriptionGroup extends BaseModel {
  id: string = '';
  stripePriceTableId: string | null = null;
  isActive: boolean | null = null;
  plans: Plan[] = [];
  createdAt: string | null = null;
  updatedAt: string | null = null;

  constructor(data?: any) {
    super();
    this.init(SubscriptionGroup, data);
    this.plans = Plan.newInstances(Plan, data?.plans);
  }
}

