import { SubscriptionGroup } from '@/models/subscription-group';
import { MandatoryOrHavingError } from '@/models/types';
import { ApiClient } from '@/services/clients/web-api-client';
import { SubscriptionGroupsApiInterface } from '@/services/interfaces/subscription-groups-api.interface';

export class SubscriptionGroupsService
  extends ApiClient
  implements SubscriptionGroupsApiInterface
{
  async getSubscriptionGroups(): Promise<
    MandatoryOrHavingError<'subscriptionGroups', SubscriptionGroup[]>
  > {
    const { errors, result } = await this.wrapForApiError<{
      subscriptionGroups: SubscriptionGroup[];
    }>(async () => {
      return await this.client.get('subscription-groups');
    });

    return this.adjustApiResultForMandatoryObject(
      'subscriptionGroups',
      SubscriptionGroup.newInstances(
        SubscriptionGroup,
        result?.subscriptionGroups,
      ),
      errors,
    );
  }
}

