import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';

part 'subscription_group.freezed.dart';
part 'subscription_group.g.dart';

@freezed
abstract class SubscriptionGroup with _$SubscriptionGroup {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: Constants.modelFieldRename,
  )
  const factory SubscriptionGroup({
    @Default(null) String? id,
    @Default(null) String? stripePriceTableId,
    @Default(null) bool? isActive,
    @Default([]) List<Plan> plans,
    @Default(null) DateTime? createdAt,
    @Default(null) DateTime? updatedAt,
  }) = _SubscriptionGroup;

  factory SubscriptionGroup.fromJson(Map<String, dynamic> json) =>
      _$SubscriptionGroupFromJson(json);
}

