  @override
  Future<Result<Failure, ResourceSearchResponse>> getResources({
    required String teamId,
    required String sessionId,
    required int page,
    required int pageSize,
    required bool isTeamCrossing,
  }) async {
    final userId = profileStorage.getUserId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/sessions/$sessionId/resources/search',
      data: ResourceSearchRequest(
        userId: isTeamCrossing ? null : userId,
        page: page,
        pageSize: pageSize,
        orderBy: ResourceSearchRequestOrderBy.createdAt,
        isOrderDesc: true,
      ).toJson(),
      responseMapper: ResourceSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }

    return Right(
      response.right.copyWith(
        resources: response.right.resources
            .map(
              (resource) => _reprocessResourceWithBallInfo(
                resource,
                teamId,
                sessionId,
                resource.session?.userId,
              ),
            )
            .toList(),
      ),
    );
  }

  @override
  Future<Result<Failure, ResourceData>> getResourceDetail({
    required String teamId,
    required String sessionId,
    required String resourceId,
