// Flutter imports:
import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/data/profile_storage.dart';
import 'package:baseball_detector_flutter/data/profile_storage_fake.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_is_on_premium_plan.dart';

class _StubTeamListController extends TeamListController {
  _StubTeamListController(this._state);

  final AsyncValue<Result<Failure, List<Team>>> _state;

  @override
  AsyncValue<Result<Failure, List<Team>>> build() => _state;

  @override
  Future<void> refreshKeepingPrevious() async {}
}

class _HookHarness extends HookConsumerWidget {
  const _HookHarness({required this.onValue});

  final ValueChanged<bool> onValue;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final value = useIsOnPremiumPlan();
    onValue(value);
    return const SizedBox.shrink();
  }
}

Future<bool> _readHook(
  WidgetTester tester, {
  required ProfileStorage profileStorage,
  required AsyncValue<Result<Failure, List<Team>>> teamListState,
}) async {
  bool? result;

  void capture(bool value) {
    result = value;
  }

  await tester.pumpWidget(
    ProviderScope(
      overrides: [
        profileStorageProvider.overrideWithValue(profileStorage),
        teamListControllerProvider.overrideWith(
          () => _StubTeamListController(teamListState),
        ),
      ],
      child: Directionality(
        textDirection: TextDirection.ltr,
        child: _HookHarness(onValue: capture),
      ),
    ),
  );

  await tester.pump();

  expect(result, isNotNull,
      reason: 'useIsOnPremiumPlan should emit synchronously inside HookHarness');
  return result!;
}

Team _buildTeam({
  required String id,
  TeamPlan? teamPlan,
  TeamType teamType = TeamType.single,
}) {
  return Team(
    id: id,
    teamType: teamType,
    teamPlan: teamPlan,
  );
}

TeamPlan _buildTeamPlan({
  required String planId,
  DateTime? endDate,
  bool isActive = true,
  bool planIsPaid = true,
}) {
  return TeamPlan(
    planId: planId,
    endDate: endDate ?? DateTime.now().add(const Duration(days: 30)),
    isActive: isActive,
    plan: Plan(
      id: planId,
      isActive: true,
      isPaid: planIsPaid,
    ),
  );
}

Result<Failure, List<Team>> _buildTeamListResult(List<Team> teams) {
  return Right(teams);
}

const _premiumPlanId = '00000001-0000-0300-0000-000000000000';
const _standardPlanId = '00000001-0000-0100-0000-000000000000';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  group('useIsOnPremiumPlan', () {
    testWidgets('プレミアムプランが有効期間内なら true を返す', (tester) async {
      final profileStorage = FakeProfileStorage(teamId: 'team-1');
      final team = _buildTeam(
        id: 'team-1',
        teamPlan: _buildTeamPlan(planId: _premiumPlanId),
      );

      final result = await _readHook(
        tester,
        profileStorage: profileStorage,
        teamListState: AsyncValue.data(_buildTeamListResult([team])),
      );

      expect(result, isTrue);
    });

    testWidgets('チームプランがプレミアム以外なら false を返す', (tester) async {
      final profileStorage = FakeProfileStorage(teamId: 'team-1');
      final team = _buildTeam(
        id: 'team-1',
        teamPlan: _buildTeamPlan(planId: _standardPlanId),
      );

      final result = await _readHook(
        tester,
        profileStorage: profileStorage,
        teamListState: AsyncValue.data(_buildTeamListResult([team])),
      );

      expect(result, isFalse);
    });

    testWidgets('チームプランが期限切れなら false を返す', (tester) async {
      final profileStorage = FakeProfileStorage(teamId: 'team-1');
      final team = _buildTeam(
        id: 'team-1',
        teamPlan: _buildTeamPlan(
          planId: _premiumPlanId,
          endDate: DateTime.now().subtract(const Duration(days: 1)),
        ),
      );

      final result = await _readHook(
        tester,
        profileStorage: profileStorage,
        teamListState: AsyncValue.data(_buildTeamListResult([team])),
      );

      expect(result, isFalse);
    });

    testWidgets('teamId が取得できない場合は false を返す', (tester) async {
      final profileStorage = FakeProfileStorage(teamId: null);
      final team = _buildTeam(
        id: 'team-1',
        teamPlan: _buildTeamPlan(planId: _premiumPlanId),
      );

      final result = await _readHook(
        tester,
        profileStorage: profileStorage,
        teamListState: AsyncValue.data(_buildTeamListResult([team])),
      );

      expect(result, isFalse);
    });

    testWidgets('チームリストがロード中なら false を返す', (tester) async {
      final profileStorage = FakeProfileStorage(teamId: 'team-1');

      final result = await _readHook(
        tester,
        profileStorage: profileStorage,
        teamListState: const AsyncValue.loading(),
      );

      expect(result, isFalse);
    });
  });
}

