// Package imports:
import 'package:collection/collection.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

bool useIsOnPremiumPlan() {
  final ref = useWidgetRef();
  final teamListState = ref.watch(teamListControllerProvider).value;
  final teamId = ref.read(profileStorageProvider).getTeamId();

  if (teamId == null || teamListState == null) {
    return false;
  }

  final teams = teamListState.hasRight ? teamListState.right : null;
  if (teams == null) {
    return false;
  }

  final team = teams.firstWhereOrNull((t) => t.id == teamId);
  final teamPlan = team?.teamPlan;
  if (teamPlan == null) {
    return false;
  }

  if (!teamPlan.withinPeriod) {
    return false;
  }

  final planId = teamPlan.planId;
  if (planId == null) {
    return false;
  }

  final planType = planToAppStoreProductMap[planId];
  return planType == PlanType.premium;
}

