// Package imports:

// Package imports:
import 'package:flutter_test/flutter_test.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/enums/app_role.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/profile.dart';
import 'package:baseball_detector_flutter/data/models/role_group.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/data/models/user_role.dart';
import '../../_common/create_accessible_contents.dart';

void main() {
  group('Testing UserInfo and UserAccessibleContents', () {
    const id = '22222222-0000-0000-0000-000000000000';
    const teamId = '11111111-0001-0000-0000-000000000000';
    final createdAt = DateTime(2024, 1, 1, 1, 1);
    final updatedAt = DateTime(2024, 1, 1, 2, 1);

    final userInfo = UserInfo(
      id: id,
      email: 'user2_team1_admin@test.com',
      deletedAt: null,
      createdAt: createdAt,
      updatedAt: updatedAt,
      profile: Profile(
        id: '00000000-0000-4000-8000-000000000000',
        username: 'test name',
        imageUrl: 'https://example.test/image.jpg',
        presignedImageUrl: 'https://example.test/image.jpg?presigned',
        createdAt: createdAt,
        updatedAt: updatedAt,
      ),
      accessibleContents: createAccessibleContents({
        teamId: [AppRole.teamAdmin]
      }),
      givenUserRoles: {
        teamId: [
          UserRole(
            id: '77777777-0003-0001-0000-000000000001',
            userId: id,
            teamId: teamId,
            roleGroupId: 'a0000000-0000-0000-0000-000000000002',
            createdAt: createdAt,
            updatedAt: updatedAt,
            deleteFlag: false,
            roleGroup: RoleGroup(
              id: 'a0000000-0000-0000-0000-000000000002',
              name: AppRole.teamAdmin,
              isAllTeamsAccess: false,
              createdAt: createdAt,
              updatedAt: updatedAt,
            ),
          ),
        ],
      },
      teams: [
        Team(
          id: teamId,
          name: 'test name',
          ownerUserId: '00000000-0000-4000-8000-000000000001',
          createdAt: createdAt,
          updatedAt: updatedAt,
          imageUrl: 'https://example.test/image.jpg',
          presignedImageUrl: 'https://example.test/image.jpg?presigned',
          teamPlan: TeamPlan(
            id: '77777777-0003-0001-0000-00000000000',
            teamId: '00000000-0000-4000-8000-000000000000',
            planId: '2',
            startDate: DateTime.utc(2023, 1, 1, 0, 0),
            endDate: DateTime.utc(2024, 1, 1, 0, 0),
            currentUsage: 0,
            isActive: true,
            extraBalls: 0,
            createdAt: createdAt,
            updatedAt: updatedAt,
            plan: Plan(
              id: '1',
              name: 'test plan',
              description: 'test description',
              type: 1,
              maxBalls: 100,
              createdAt: createdAt,
              updatedAt: updatedAt,
            ),
          ),
        ),
      ],
    );

    test('toJson1', () {
      final userInfoJson = userInfo.toJson();

      expect(userInfoJson.length, 9);

      expect(userInfoJson.containsKey('id'), isTrue);
      expect(userInfoJson.containsKey('email'), isTrue);
      expect(userInfoJson.containsKey('deletedAt'), isTrue);
      expect(userInfoJson.containsKey('createdAt'), isTrue);
      expect(userInfoJson.containsKey('updatedAt'), isTrue);
      expect(userInfoJson.containsKey('profile'), isTrue);
      expect(userInfoJson.containsKey('accessibleContents'), isTrue);
      expect(userInfoJson.containsKey('givenUserRoles'), isTrue);
      expect(userInfoJson.containsKey('teams'), isTrue);

      expect(userInfoJson['id'], userInfo.id);
      expect(userInfoJson['email'], userInfo.email);
      expect(userInfoJson['deletedAt'], userInfo.deletedAt?.toIso8601String());
      expect(userInfoJson['createdAt'], userInfo.createdAt?.toIso8601String());
      expect(userInfoJson['updatedAt'], userInfo.updatedAt?.toIso8601String());
      expect(userInfoJson['profile'], userInfo.profile.toJson());
      expect(userInfoJson['accessibleContents'],
          userInfo.accessibleContents.toJson());
      expect(userInfoJson['givenUserRoles'][teamId].length, 1);
      expect(userInfoJson['givenUserRoles'][teamId][0],
          userInfo.givenUserRoles[teamId]![0].toJson());
      expect(userInfoJson['teams'].length, 1);
      expect(userInfoJson['teams'][0], userInfo.teams[0].toJson());

      final deserializedUserInfo = UserInfo.fromJson(userInfoJson);
      expect(deserializedUserInfo, userInfo);
    });

    test('fromJson1 (API New)', () {
      final teamAccessibleContents = userInfo.accessibleContents[teamId]!;
      final teamBasic = teamAccessibleContents[RoleDomain.basic]!;
      final teamBasicRead = teamBasic[RoleLevel.read]!;
      final teamBasicWrite = teamBasic[RoleLevel.write]!;
      final teamBasicAdmin = teamBasic[RoleLevel.admin]!;
      final teamManagement = teamAccessibleContents[RoleDomain.management]!;
      final teamManagementRead = teamManagement[RoleLevel.read]!;
      final teamManagementWrite = teamManagement[RoleLevel.write]!;
      final teamManagementAdmin = teamManagement[RoleLevel.admin]!;
      final userRole = userInfo.givenUserRoles[teamId]![0];

      final userInfoJson = {
        'id': userInfo.id,
        'email': userInfo.email,
        'deletedAt': userInfo.deletedAt?.toIso8601String(),
        'createdAt': userInfo.createdAt?.toIso8601String(),
        'updatedAt': userInfo.updatedAt?.toIso8601String(),
        'profile': userInfo.profile.toJson(),
        'accessibleContents': {
          teamId: {
            'basic': {
              'read': {
                'isAccessible': teamBasicRead.isAccessible,
                'isTeamCrossing': teamBasicRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamBasicWrite.isAccessible,
                'isTeamCrossing': teamBasicWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamBasicAdmin.isAccessible,
                'isTeamCrossing': teamBasicAdmin.isTeamCrossing,
              },
            },
            'management': {
              'read': {
                'isAccessible': teamManagementRead.isAccessible,
                'isTeamCrossing': teamManagementRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamManagementWrite.isAccessible,
                'isTeamCrossing': teamManagementWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamManagementAdmin.isAccessible,
                'isTeamCrossing': teamManagementAdmin.isTeamCrossing,
              },
            }
          }
        },
        'givenUserRoles': {
          teamId: [
            userRole.toJson(),
          ],
        },
        'teams': [
          userInfo.teams[0].toJson(),
        ],
      };

      final deserialized = UserInfo.fromJson(userInfoJson);

      expect(deserialized.id, userInfo.id);
      expect(deserialized.email, userInfo.email);
      expect(deserialized.deletedAt, userInfo.deletedAt);
      expect(deserialized.createdAt, userInfo.createdAt);
      expect(deserialized.updatedAt, userInfo.updatedAt);
      expect(deserialized.profile, userInfo.profile);
      expect(deserialized.givenUserRoles, userInfo.givenUserRoles);
      expect(deserialized.accessibleContents, userInfo.accessibleContents);
      expect(deserialized.teams, userInfo.teams);

      final serializedJson = deserialized.toJson();
      expect(serializedJson, userInfoJson);
    });
    test('fromJson1 (API Old)', () {
      final teamAccessibleContents = userInfo.accessibleContents[teamId]!;
      final teamBasic = teamAccessibleContents[RoleDomain.basic]!;
      final teamBasicRead = teamBasic[RoleLevel.read]!;
      final teamBasicWrite = teamBasic[RoleLevel.write]!;
      final teamBasicAdmin = teamBasic[RoleLevel.admin]!;
      final teamManagement = teamAccessibleContents[RoleDomain.management]!;
      final teamManagementRead = teamManagement[RoleLevel.read]!;
      final teamManagementWrite = teamManagement[RoleLevel.write]!;
      final teamManagementAdmin = teamManagement[RoleLevel.admin]!;
      final userRole = userInfo.givenUserRoles[teamId]![0];

      final userInfoJson = {
        'id': userInfo.id,
        'email': userInfo.email,
        'deletedAt': userInfo.deletedAt?.toIso8601String(),
        'createdAt': userInfo.createdAt?.toIso8601String(),
        'updatedAt': userInfo.updatedAt?.toIso8601String(),
        'profile': userInfo.profile.toJson(),
        'accessibleContents': {
          teamId: {
            'basic': {
              'read': {
                'isAccessible': teamBasicRead.isAccessible,
                'isTeamCrossing': teamBasicRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamBasicWrite.isAccessible,
                'isTeamCrossing': teamBasicWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamBasicAdmin.isAccessible,
                'isTeamCrossing': teamBasicAdmin.isTeamCrossing,
              },
            },
            'management': {
              'read': {
                'isAccessible': teamManagementRead.isAccessible,
                'isTeamCrossing': teamManagementRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamManagementWrite.isAccessible,
                'isTeamCrossing': teamManagementWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamManagementAdmin.isAccessible,
                'isTeamCrossing': teamManagementAdmin.isTeamCrossing,
              },
            }
          }
        },
        'givenUserRoles': {
          teamId: [
            userRole.toJson(),
          ],
        },
        'teams': [
          userInfo.teams[0].toJson(),
        ],
      };

      final deserialized = UserInfo.fromJson(userInfoJson);

      expect(deserialized.id, userInfo.id);
      expect(deserialized.email, userInfo.email);
      expect(deserialized.deletedAt, userInfo.deletedAt);
      expect(deserialized.createdAt, userInfo.createdAt);
      expect(deserialized.updatedAt, userInfo.updatedAt);
      expect(deserialized.profile, userInfo.profile);
      expect(deserialized.givenUserRoles, userInfo.givenUserRoles);
      expect(deserialized.accessibleContents, userInfo.accessibleContents);
      expect(deserialized.teams, userInfo.teams);

      final serializedJson = deserialized.toJson();
      expect(serializedJson, userInfoJson);
    });
    test('fromJson1 (API Old, int id)', () {
      final teamAccessibleContents = userInfo.accessibleContents[teamId]!;
      final teamBasic = teamAccessibleContents[RoleDomain.basic]!;
      final teamBasicRead = teamBasic[RoleLevel.read]!;
      final teamBasicWrite = teamBasic[RoleLevel.write]!;
      final teamBasicAdmin = teamBasic[RoleLevel.admin]!;
      final teamManagement = teamAccessibleContents[RoleDomain.management]!;
      final teamManagementRead = teamManagement[RoleLevel.read]!;
      final teamManagementWrite = teamManagement[RoleLevel.write]!;
      final teamManagementAdmin = teamManagement[RoleLevel.admin]!;
      final userRole = userInfo.givenUserRoles[teamId]![0];
      // UserRoleのidをintで、TeamPlanのidをintで上書き
      final userRoleJson = Map<String, dynamic>.from(userRole.toJson());
      userRoleJson['id'] = 12345; // int型id
      final teamJson = Map<String, dynamic>.from(userInfo.teams[0].toJson());
      final teamPlanJson = Map<String, dynamic>.from(teamJson['teamPlan']);
      teamPlanJson['id'] = 67890; // int型id
      teamJson['teamPlan'] = teamPlanJson;
      final userInfoJson = {
        'id': userInfo.id,
        'email': userInfo.email,
        'deletedAt': userInfo.deletedAt?.toIso8601String(),
        'createdAt': userInfo.createdAt?.toIso8601String(),
        'updatedAt': userInfo.updatedAt?.toIso8601String(),
        'profile': userInfo.profile.toJson(),
        'accessibleContents': {
          teamId: {
            'basic': {
              'read': {
                'isAccessible': teamBasicRead.isAccessible,
                'isTeamCrossing': teamBasicRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamBasicWrite.isAccessible,
                'isTeamCrossing': teamBasicWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamBasicAdmin.isAccessible,
                'isTeamCrossing': teamBasicAdmin.isTeamCrossing,
              },
            },
            'management': {
              'read': {
                'isAccessible': teamManagementRead.isAccessible,
                'isTeamCrossing': teamManagementRead.isTeamCrossing,
              },
              'write': {
                'isAccessible': teamManagementWrite.isAccessible,
                'isTeamCrossing': teamManagementWrite.isTeamCrossing,
              },
              'admin': {
                'isAccessible': teamManagementAdmin.isAccessible,
                'isTeamCrossing': teamManagementAdmin.isTeamCrossing,
              },
            }
          }
        },
        'givenUserRoles': {
          teamId: [userRoleJson],
        },
        'teams': [teamJson],
      };

      final deserialized = UserInfo.fromJson(userInfoJson);

      expect(deserialized.id, userInfo.id);
      expect(deserialized.email, userInfo.email);
      expect(deserialized.deletedAt, userInfo.deletedAt);
      expect(deserialized.createdAt, userInfo.createdAt);
      expect(deserialized.updatedAt, userInfo.updatedAt);
      expect(deserialized.profile, userInfo.profile);
      // idはString化されているはずなので、他のフィールドで比較
      expect(deserialized.givenUserRoles[teamId]![0].userId, userRole.userId);
      expect(deserialized.givenUserRoles[teamId]![0].roleGroupId,
          userRole.roleGroupId);
      expect(deserialized.accessibleContents, userInfo.accessibleContents);
      expect(deserialized.teams[0].name, userInfo.teams[0].name);
      expect(deserialized.teams[0].teamPlan?.plan?.id,
          userInfo.teams[0].teamPlan?.plan?.id);
      // toJsonでidがString化されることも確認
      final serializedJson = deserialized.toJson();
      expect(serializedJson['givenUserRoles'][teamId][0]['id'].toString(),
          '12345');
      expect(serializedJson['teams'][0]['teamPlan']['id'].toString(), '67890');
    });
  });
}
